void
userinit(void)
{
  struct proc *p;
  uint64 initcode_sz = _initcode_end - _initcode_start;
  uint64 prog_sz = PGROUNDUP(initcode_sz + PGSIZE);

  p = allocproc();
  initproc = p;

  printf("initcode start: %p\n", _initcode_start);
  printf("initcode end: %p\n", _initcode_end);
  printf("initcode size: %d\n", initcode_sz);

  // allocate one user page and copy initcode's instructions
  // and data into it.
  p->sz = uvmalloc(p->pagetable, p->sz, prog_sz, PTE_W|PTE_R|PTE_X|PTE_U);
  if(p->sz == 0){
    panic("userinit: uvmalloc");
  }
  // printf("pa: %p\n", walkaddr(p->pagetable, 0));
  copyout(p->pagetable, 0, (char*)_initcode_start, initcode_sz);

  // prepare for the very first "return" from kernel to user.
  p->trapframe->epc = 0;      // user program counter
  p->trapframe->sp = prog_sz;  // user stack pointer

  safestrcpy(p->name, "initcode", sizeof(p->name));
  // p->cwd = namei("/");
  safestrcpy(p->cwd_path, "/", MAXPATH);

  p->state = RUNNABLE;

  struct file *f = filealloc();
  f->major = 1;
  f->ip = 0;
  f->readable = 1;
  f->writable = 1;
  f->type = FD_DEVICE;
  filedup(f);
  filedup(f);
  p->ofile[0].f = f;
  p->ofile[1].f = f;
  p->ofile[2].f = f;

  release(&p->lock);
}

// Grow or shrink user memory by n bytes.
// Return 0 on success, -1 on failure.
int
growproc(int n)
{
  uint64 sz;
  struct proc *p = myproc();

  sz = p->sz;
  if(n > 0){
    if((sz = uvmalloc(p->pagetable, sz, sz + n, PTE_W)) == 0) {
      return -1;
    }
  } else if(n < 0){
    sz = uvmdealloc(p->pagetable, sz, sz + n);
  }
  p->sz = sz;
  return 0;
}

