// Fetch the nth word-sized system call argument as a file descriptor
// and return both the descriptor and the corresponding struct file.
static int
argfd(int n, int *pfd, struct file **pf)
{
  int fd;
  struct file *f;

  argint(n, &fd);
  if(fd < 0 || fd >= NOFILE || (f=myproc()->ofile[fd].f) == 0)
    return -1;
  if(pfd)
    *pfd = fd;
  if(pf)
    *pf = f;
  return 0;
}

// Allocate a file descriptor for the given file.
// Takes over file reference from caller on success.
static int
fdalloc(struct file *f)
{
  int fd;
  struct proc *p = myproc();

  for(fd = 0; fd < NOFILE; fd++){
    if(p->ofile[fd].f == 0){
      p->ofile[fd].f = f;
      p->ofile[fd].flags = 0;
      return fd;
    }
  }
  return -1;
}

int
makeatpath(char *path, struct proc *p, int dfd, char *filename)
{
  if(filename[0] == '/')
    safestrcpy(path, filename, MAXPATH);
  else{
    if(dfd == AT_FDCWD)
      safestrcpy(path, p->cwd_path, MAXPATH);
    else if(dfd < 0 || dfd >= NOFILE || p->ofile[dfd].f == 0)
      return -1;
    else
      safestrcpy(path, p->ofile[dfd].f->path, MAXPATH);
    safepathcat(path, filename, MAXPATH);
  }
  return 0;
}

