uint64
sys_writev(int fd, uint64 iovp, int iovcnt)
{
  struct iovec iov;
  struct file *f;
  int w, wd, tot = 0;
  struct proc *p = myproc();

  if(argfd(0, 0, &f) < 0)
    return -EBADF;
  for(int i = 0; i < iovcnt; ++i){
    if(copyin(p->pagetable, (char*)&iov, iovp+i*sizeof(iov), sizeof(iov)) < 0)
      return -EFAULT;
    wd = 0;
    while(wd < iov.iov_len){
      w = filewrite(f, i + (uint64)iov.iov_base, iov.iov_len - wd);
      if(w == 0)
        return tot;
      if(w < 0)
        return -EBADF;
      tot += w;
      wd += w;
    }
  }
  return tot;
}

