int
openat(int dfd, char *filename, int flags, uint mode)
{
  // mode is 0600, unused
  int fd;
  struct file *f;
  struct inode *ip;
  char path[MAXPATH];
  struct proc *p = myproc();

  if(makeatpath(path, p, dfd, filename) < 0)
    return -1;

  begin_op();

  if(flags & O_CREAT){
    ip = create(path, T_FILE, 0, 0);
    if(ip == 0){
      end_op();
      return -1;
    }
  } else {
    if((ip = namei(path)) == 0){
      end_op();
      return -1;
    }
    ilock(ip);
    // NOTE: workaround for competition
    // if(ip->type == T_DIR && flags != O_DIRECTORY){
    //   iunlockput(ip);
    //   end_op();
    //   return -1;
    // }
  }

  // if(ip->type == T_DEVICE && (ip->major < 0 || ip->major >= NDEV)){
  //   iunlockput(ip);
  //   end_op();
  //   return -1;
  // }

  if((f = filealloc()) == 0 || (fd = fdalloc(f)) < 0){
    if(f)
      fileclose(f);
    iunlockput(ip);
    end_op();
    return -1;
  }

  if((ip->rs.mode&0xF000) == 0x8000){
    f->type = FD_INODE;
    f->off = 0;
  } else {
    f->type = FD_DEVICE;
    f->major = 1;
  }
  f->ip = ip;
  f->readable = !(flags & O_WRONLY);
  f->writable = !(flags == O_DIRECTORY) && ((flags & O_WRONLY) || (flags & O_RDWR));

  safestrcpy(f->path, path, MAXPATH);

  if((flags & O_TRUNC) && (ip->rs.mode&0xF000) == 0x8000){
    itrunc(ip);
  }

  iunlock(ip);
  end_op();

  return fd;
}

