pub fn do_inode_read(inum: u32, p: *mut Ext4InodeRef) -> i32 {
    unsafe {
        let fs = EXT4FS.assume_init_ref();
        p.write(fs.get_inode_ref(inum));
    }
    0
}

pub fn do_inode_writeback(ip: &mut Ext4InodeRef) {
    unsafe {
        let fs = EXT4FS.assume_init_ref();
        fs.write_back_inode(ip);
    }
}

pub fn do_itrunc(p: *mut Ext4InodeRef) {
    unsafe {
        let fs = EXT4FS.assume_init_ref();
        fs.truncate_inode(&mut *p, 0).ok();
    }
}

pub fn do_readi(ip: *const Ext4InodeRef, user_dst: i32, dst: u64, off: u32, n: u32) -> i32 {
    let mut v = vec![0u8; n as _];
    unsafe {
        let fs = EXT4FS.assume_init_ref();
        // println!("rs::readi: i: {} off: {}", (*ip).inode_num, off);
        let len = fs.read_at((*ip).inode_num, off as _, &mut v).unwrap();
        either_copyout(user_dst, dst, v.as_mut_ptr() as _, len as _);
        len as _
    }
}

pub fn do_writei(ino: u32, user_src: c_int, src: c_ulonglong, off: u32, n: u32) -> i32 {
    let fs = unsafe { EXT4FS.assume_init_ref() };
    let mut buf = vec![0u8; n as _];
    unsafe { either_copyin(buf.as_mut_ptr() as _, user_src, src, n as _) };
    fs.write_at(ino, off as _, &buf).unwrap() as _
}

pub fn do_dirlookup(idir: u32, name: &str) -> u32 {
    let fs = unsafe { EXT4FS.assume_init_ref() };
    let mut res = Ext4DirSearchResult::new(Ext4DirEntry::default());
    if fs.dir_find_entry(idir, name, &mut res).is_ok() {
        res.dentry.inode
    } else {
        0
    }
}

pub fn do_unlink(path: &str) -> i32 {
    let fs = unsafe { EXT4FS.assume_init_ref() };
    if fs.file_remove(path).is_ok() {
        0
    } else {
        -1
    }
}

pub fn do_create(idir: u32, name: &str, typ: u32) -> u32 {
    let fs = unsafe { EXT4FS.assume_init_ref() };
    let mut res = Ext4DirSearchResult::new(Ext4DirEntry::default());
    if fs.dir_find_entry(idir, name, &mut res).is_ok() {
        let inode_typ = fs.get_inode_ref(res.dentry.inode).inode.mode & EXT4_INODE_MODE_TYPE_MASK;
        if typ == T_FILE
            && match inode_typ as usize {
                EXT4_INODE_MODE_REG | EXT4_INODE_MODE_BLK | EXT4_INODE_MODE_CHR => true,
                _ => false,
            }
        {
            return res.dentry.inode;
        }
    }
    let mode = match typ {
        T_FILE => EXT4_INODE_MODE_REG,
        T_DIR => EXT4_INODE_MODE_DIR,
        T_DEVICE => EXT4_INODE_MODE_BLK,
        _ => panic!("create: unsupported type: {}", typ),
    } as u16
        | EXT4_INODE_MODE_PERM_MASK;
    if let Ok(i) = fs.create(idir, name, mode) {
        i.inode_num
    } else {
        0
    }
}

pub fn do_getdents(inum: u32, bufva: usize, len: i32) -> i32 {
    let fs = unsafe { EXT4FS.assume_init_ref() };
    let mut buf = vec![0u8; len as _];
    let dents = fs.dir_get_entries(inum);
    let mut p: usize = 0;
    for ent in dents {
        let reclen = size_of::<LinuxDirent64>() as u16 + ent.name_len as u16 + 1;
        if p + reclen as usize > len as usize {
            break;
        }
        let de = buf.as_mut_ptr() as *mut LinuxDirent64;
        unsafe {
            (*de).d_ino = ent.inode as _;
            (*de).d_type = ent.get_de_type();
            (*de).d_reclen = reclen;
            either_copyout(
                0,
                (*de).d_name.as_mut_ptr() as _,
                addr_of!(ent.name) as _,
                ent.name_len as _,
            );
        }
        p += reclen as usize;
    }
    unsafe { either_copyout(1, bufva as _, buf.as_ptr() as _, p as _) };
    p as _
}

