struct PoolInternal<T, const N: usize> {
    lock: SpinLock,
    data: [UnsafeCell<(usize, Option<T>)>; N],
}

impl<T, const N: usize> PoolInternal<T, N> {
    fn unlock(&mut self) {
        unsafe { release(addr_of_mut!(self.lock)) };
    }
}

pub struct Pool<T, const N: usize> {
    internal: UnsafeCell<MaybeUninit<PoolInternal<T, N>>>,
}

unsafe impl<T, const N: usize> Sync for Pool<T, N> {}

impl<T, const N: usize> Pool<T, N> {
    pub const fn new_uninit() -> Self {
        Self {
            internal: UnsafeCell::new(MaybeUninit::uninit()),
        }
    }
    pub unsafe fn init(&self, name: *const c_char) {
        let internal = self.internal.get().as_mut().unwrap_unchecked();
        let internal = internal.assume_init_mut();
        internal.lock = SpinLock::new(name as _);
        for p in &mut internal.data {
            from_mut(p).write((0, None).into());
        }
    }
    fn internal_lock(&self) -> &mut PoolInternal<T, N> {
        let internal = unsafe { self.internal.get().as_mut().unwrap_unchecked() };
        let internal = unsafe { internal.assume_init_mut() };
        unsafe { acquire(addr_of_mut!(internal.lock)) };
        internal
    }
    fn internal_unlock(&self) {
        let internal = unsafe { self.internal.get().as_mut().unwrap_unchecked() };
        let internal = unsafe { internal.assume_init_mut() };
        unsafe { release(addr_of_mut!(internal.lock)) };
    }
    pub fn alloc(&self, f: impl FnOnce() -> T) -> Option<PoolRef<T, N>> {
        let internal = self.internal_lock();
        let mut ret = None;
        for j in &mut internal.data {
            let i = unsafe { j.get().as_mut().unwrap_unchecked() };
            if i.1.is_none() {
                assert_eq!(i.0, 0);
                i.1.replace(f());
                i.0 += 1;
                ret = Some(PoolRef {
                    pool: self,
                    target: j,
                });
                break;
            }
        }
        self.internal_unlock();
        ret
    }
}

pub struct PoolRef<'a, T, const N: usize> {
    pool: &'a Pool<T, N>,
    target: &'a UnsafeCell<(usize, Option<T>)>,
}

impl<'a, T, const N: usize> Drop for PoolRef<'a, T, N> {
    fn drop(&mut self) {
        self.pool.internal_lock();
        let target = unsafe { self.target.get().as_mut().unwrap_unchecked() };
        assert!(target.0 > 0 && target.1.is_some());
        target.0 -= 1;
        if target.0 == 0 {
            target.1.take();
        }
        self.pool.internal_unlock();
    }
}

impl<'a, T, const N: usize> PoolRef<'a, T, N> {
    fn dup(&'a self) -> Self {
        self.pool.internal_lock();
        let target = unsafe { self.target.get().as_mut().unwrap_unchecked() };
        assert!(target.0 > 0 && target.1.is_some());
        target.0 += 1;
        let ret = Self {
            pool: self.pool,
            target: self.target,
        };
        self.pool.internal_unlock();
        ret
    }
}

impl<'a, T, const N: usize> Deref for PoolRef<'a, T, N> {
    type Target = T;
    fn deref(&self) -> &Self::Target {
        unsafe {
            self.target
                .get()
                .as_ref()
                .unwrap_unchecked()
                .1
                .as_ref()
                .unwrap()
        }
    }
}

