int flags2perm(int flags)
{
    int perm = 0;
    if(flags & 0x1)
      perm = PTE_X;
    if(flags & 0x2)
      perm |= PTE_W;
    return perm;
}

int shebang_delegate(char *path, char **argv, char **envp)
{
  char *b_argv[MAXARG + 3] = {"/busybox", "sh", path, 0};
  for(int i = 0; i < MAXARG && argv[i]; ++i)
    b_argv[i+3] = argv[i];
  return execve(b_argv[0], b_argv, envp);
}

int
execve(char *path, char **argv, char **envp)
{
  char *s, *last;
  int i, off, ustackbot = 0;
  uint64 argc, envc, sz = 0, sp, ustack[MAXARG + 2], stackbase;
  struct elfhdr elf;
  struct inode *ip;
  struct proghdr ph;
  pagetable_t pagetable = 0, oldpagetable;
  struct proc *p = myproc();
  uint64 interp_start_addr = 0;

  begin_op();

  if((ip = namei(path)) == 0){
    end_op();
    return -1;
  }
  ilock(ip);
/*
  unsigned long x = 0;
  unsigned char y = 0;
  unsigned long z = 0;
  while((x=readi(ip, 0, (uint64)test, z, 256)) > 0){
    for(int i = 0; i < x; ++i){
      y ^= test[i];
    }
    z += x;
  }
  printf("%x %d\n", y&0xff, z);
*/
/*
  int x = 0;
  printf("test begin\n");
  x = 0;
  x=readi(ip, 0, (uint64)test, 0, 16);
  printf("%d\n", x);
  for(int i = 0; i < x; ++i){
    printf("%d ", ((int)test[i])&0xff);
  }
  printf("\n");
  printf("test 2\n");
  x = 0;
  x=readi(ip, 0, (uint64)test, 8190, 16);
  printf("%d\n", x);
  for(int i = 0; i < x; ++i){
    printf("%d ", ((int)test[i])&0xff);
  }
  printf("\n");
  panic("test");
*/
  if(readi(ip, 0, (uint64)&elf.magic, 0, 4) != 4 || elf.magic != ELF_MAGIC){
    iunlockput(ip);
    end_op();
    return shebang_delegate(path, argv, envp);
  }
  // Check ELF header
  if(readi(ip, 0, (uint64)&elf, 0, sizeof(elf)) != sizeof(elf))
    goto bad;

  if(elf.magic != ELF_MAGIC)
    goto bad;

  if((pagetable = proc_pagetable(p)) == 0)
    goto bad;

  // Load program into memory.
  for(i=0, off=elf.phoff; i<elf.phnum; i++, off+=sizeof(ph)){
    if(readi(ip, 0, (uint64)&ph, off, sizeof(ph)) != sizeof(ph))
      goto bad;
    if(ph.type != ELF_PROG_LOAD)
      continue;
    if(ph.memsz < ph.filesz)
      goto bad;
    if(ph.vaddr + ph.memsz < ph.vaddr)
      goto bad;
    // if(ph.vaddr % PGSIZE != 0)
    //   goto bad;
    uint64 sz1;
    if((sz1 = uvmalloc(pagetable, sz, ph.vaddr + ph.memsz, flags2perm(ph.flags))) == 0)
      goto bad;
    sz = sz1;
    if(loadseg(pagetable, ph.vaddr, ip, ph.off, ph.filesz) < 0)
      goto bad;
  }
  iunlockput(ip);
  end_op();
  ip = 0;

  p = myproc();
  uint64 oldsz = p->sz;

  // Allocate USTACKPG+1 pages at the next page boundary.
  // Make the first inaccessible as a stack guard.
  // Use the rest as the user stack.
  sz = PGROUNDUP(sz);
  uint64 sz1;
  if((sz1 = uvmalloc(pagetable, sz, sz + (USTACKPG+1)*PGSIZE, PTE_W)) == 0)
    goto bad;
  sz = sz1;
  uvmclear(pagetable, sz-(USTACKPG+1)*PGSIZE);
  sp = sz;
  stackbase = sp - USTACKPG * PGSIZE;
  // printf("stack bottom: %p\n", sp);
  // printf("stack top: %p\n", stackbase);

  memset(ustack, 0, sizeof(ustack));

  // Push argument strings, prepare rest of stack in ustack.
  for(argc = 0; argv&&argv[argc]; argc++) {
    // printf("exec: argv[%d]: %s\n", argc, argv[argc]);
    if(argc+1 >= MAXARG)
      goto bad;
    sp -= strlen(argv[argc]) + 1;
    sp -= sp % 16; // riscv sp must be 16-byte aligned
    if(sp < stackbase)
      goto bad;
    if(copyout(pagetable, sp, argv[argc], strlen(argv[argc]) + 1) < 0)
      goto bad;
    ustack[argc+1] = sp;
  }
  /*
	 * When argv is empty, add an empty string ("") as argv[0] to
	 * ensure confused userspace programs that start processing
	 * from argv[1] won't end up walking envp. See also
	 * bprm_stack_limits().
	 */
  if(argc == 0){
    sp -= 16;
    if(copyoutstr(pagetable, sp, "", 2) < 0)
      goto bad;
    ustack[1] = sp;
    argc = 1;
  }
  ustack[argc+1] = 0;
  ustack[0] = argc;
  ustackbot = argc + 1 + 1;

  for(envc = 0; envp&&envp[envc]; envc++) {
    // printf("exec: envp[%d]: %s\n", envc, envp[envc]);
    if(envc+1 >= MAXARG)
      goto bad;
    sp -= strlen(envp[envc]) + 1;
    sp -= sp % 16; // riscv sp must be 16-byte aligned
    if(sp < stackbase)
      goto bad;
    if(copyout(pagetable, sp, envp[envc], strlen(envp[envc]) + 1) < 0)
      goto bad;
    ustack[ustackbot++] = sp;
    if(ustackbot+1 >= MAXARG)
      goto bad;
  }
  ustack[ustackbot++] = 0;

  uint64 random[2] = {0xcde142a16cb93072, 0x128a39c127d8bbf2};
  sp -= 16;
  if (sp < stackbase || copyout(pagetable, sp, (char *)random, 16) < 0)
    goto bad;

#define alloc_aux(x, y)       \
    if(ustackbot+4 >= MAXARG) \
      goto bad;               \
    ustack[ustackbot++] = x;  \
    ustack[ustackbot++] = y;
  alloc_aux(AT_HWCAP, 0);
  alloc_aux(AT_PAGESZ, PGSIZE);
  alloc_aux(AT_PHDR, ph.vaddr);
  alloc_aux(AT_PHENT, elf.phentsize);
  alloc_aux(AT_PHNUM, elf.phnum);
  alloc_aux(AT_BASE, interp_start_addr);
  alloc_aux(AT_ENTRY, elf.entry);
  alloc_aux(AT_UID, 0);
  alloc_aux(AT_EUID, 0);
  alloc_aux(AT_GID, 0);
  alloc_aux(AT_EGID, 0);
  alloc_aux(AT_SECURE, 0);
  alloc_aux(AT_RANDOM, sp);
  alloc_aux(AT_NULL, 0);
#undef alloc_aux

  ustack[ustackbot++] = 0;

  // printf("exec: ustack:\n");
  // for(int i = 0; i < ustackbot; ++i)
  //   printf("%p\n", ustack[i]);

  // push the array of argv[] pointers.
  sp -= ustackbot * sizeof(ustack[0]);
  sp -= sp % 16;
  if(sp < stackbase)
    goto bad;
  if(copyout(pagetable, sp, (char *)ustack, ustackbot*sizeof(uint64)) < 0)
    goto bad;

  // Save program name for debugging.
  for(last=s=path; *s; s++)
    if(*s == '/')
      last = s+1;
  safestrcpy(p->name, last, sizeof(p->name));

  // Commit to the user image.
  oldpagetable = p->pagetable;
  p->pagetable = pagetable;
  p->sz = sz;
  memset(p->trapframe, 0, sizeof(struct trapframe));
  p->trapframe->epc = elf.entry;  // initial program counter = main
  p->trapframe->sp = sp; // initial stack pointer
  proc_freepagetable(oldpagetable, oldsz);

  // printf("exec: pc: %p sp: %p\n", p->trapframe->epc, p->trapframe->sp);
  // printf("exec ok\n");

  return 0;

 bad:
  if(pagetable)
    proc_freepagetable(pagetable, sz);
  if(ip){
    iunlockput(ip);
    end_op();
  }
  return -1;
}

// Load a program segment into pagetable at virtual address va.
// va may not be page-aligned;
// the pages from va to va+sz must already be mapped.
// Returns 0 on success, -1 on failure.
static int
loadseg(pagetable_t pagetable, uint64 va, struct inode *ip, uint offset, uint sz)
{
  uint i, n;
  uint64 pa;

  for(i = 0; i < sz; i += n){
    pa = walkaddr(pagetable, va + i);
    if(pa == 0)
      panic("loadseg: address should exist");
    if(sz - i < PGSIZE - (va+i) % PGSIZE)
      n = sz - i;
    else
      n = PGSIZE - (va+i) % PGSIZE;
    if(readi(ip, 0, (uint64)pa, offset+i, n) != n)
      return -1;
  }

  return 0;
}

// Buffer cache.
//
// The buffer cache is a linked list of buf structures holding
// cached copies of disk block contents.  Caching disk blocks
// in memory reduces the number of disk reads and also provides
// a synchronization point for disk blocks used by multiple processes.
//
// Interface:
// * To get a buffer for a particular disk block, call bread.
// * After changing buffer data, call bwrite to write it to disk.
// * When done with the buffer, call brelse.
// * Do not use the buffer after calling brelse.
// * Only one process at a time can use a buffer,
//     so do not keep them longer than necessary.


#include "types.h"
#include "param.h"
#include "spinlock.h"
#include "sleeplock.h"
#include "riscv.h"
#include "defs.h"
#include "fs.h"
#include "buf.h"
#include "memlayout.h"

struct {
  struct spinlock lock;
  struct buf buf[NBUF];

  // Linked list of all buffers, through prev/next.
  // Sorted by how recently the buffer was used.
  // head.next is most recent, head.prev is least.
  struct buf head;
} bcache;

void
binit(void)
{
  struct buf *b;

  initlock(&bcache.lock, "bcache");

  // Create linked list of buffers
  bcache.head.prev = &bcache.head;
  bcache.head.next = &bcache.head;
  for(b = bcache.buf; b < bcache.buf+NBUF; b++){
    b->next = bcache.head.next;
    b->prev = &bcache.head;
    initsleeplock(&b->lock, "buffer");
    bcache.head.next->prev = b;
    bcache.head.next = b;
  }
}

// Look through buffer cache for block on device dev.
// If not found, allocate a buffer.
// In either case, return locked buffer.
static struct buf*
bget(uint dev, uint blockno)
{
  struct buf *b;

  acquire(&bcache.lock);

  // Is the block already cached?
  for(b = bcache.head.next; b != &bcache.head; b = b->next){
    if(b->dev == dev && b->blockno == blockno){
      b->refcnt++;
      release(&bcache.lock);
      acquiresleep(&b->lock);
      return b;
    }
  }

  // Not cached.
  // Recycle the least recently used (LRU) unused buffer.
  for(b = bcache.head.prev; b != &bcache.head; b = b->prev){
    if(b->refcnt == 0) {
      b->dev = dev;
      b->blockno = blockno;
      b->valid = 0;
      b->refcnt = 1;
      release(&bcache.lock);
      acquiresleep(&b->lock);
      return b;
    }
  }
  panic("bget: no buffers");
}

// Return a locked buf with the contents of the indicated block.
struct buf*
bread(uint dev, uint blockno)
{
  struct buf *b;

  b = bget(dev, blockno);
  if(!b->valid) {
    memmove(b->data, (void*)(BSIZE*b->blockno+MEMDISK), BSIZE);
    // virtio_disk_rw(b, 0);
    b->valid = 1;
  }
  return b;
}

// Write b's contents to disk.  Must be locked.
void
bwrite(struct buf *b)
{
  if(!holdingsleep(&b->lock))
    panic("bwrite");
  memmove((void*)(BSIZE*b->blockno+MEMDISK), b->data, BSIZE);
  // virtio_disk_rw(b, 1);
}

// Release a locked buffer.
// Move to the head of the most-recently-used list.
void
brelse(struct buf *b)
{
  if(!holdingsleep(&b->lock))
    panic("brelse");

  releasesleep(&b->lock);

  acquire(&bcache.lock);
  b->refcnt--;
  if (b->refcnt == 0) {
    // no one is waiting for it.
    b->next->prev = b->prev;
    b->prev->next = b->next;
    b->next = bcache.head.next;
    b->prev = &bcache.head;
    bcache.head.next->prev = b;
    bcache.head.next = b;
  }

  release(&bcache.lock);
}

void
bpin(struct buf *b) {
  acquire(&bcache.lock);
  b->refcnt++;
  release(&bcache.lock);
}

void
bunpin(struct buf *b) {
  acquire(&bcache.lock);
  b->refcnt--;
  release(&bcache.lock);
}

int
breadoffset(uint dev, uint64 off, void *addr, uint64 max)
{
  uint blknr = off / BSIZE;
  uint blkoff = off % BSIZE;
  // printf("breadoffset: blknr: %d blkoff: %d\n", blknr, blkoff);
  int n = max;
  if(BSIZE - blkoff < n)
    n = BSIZE - blkoff;
  struct buf *b = bread(dev, blknr);
  memmove(addr,&b->data[blkoff],n);
  brelse(b);
  return n;
}

#define min(x,y) ((x)<(y)?(x):(y))

void
bwriteoffset(uint dev, uint64 off, const void *addr, uint64 n)
{
  uint64 tot;
  struct buf *bp;
  uint64 m;
  for(tot=0; tot<n; tot+=m, off+=m, addr+=m){
    bp = bread(dev, off / BSIZE);
    m = min(BSIZE-off%BSIZE, n-tot);
    memmove(&bp->data[off%BSIZE], addr, m);
    bwrite(bp);
    brelse(bp);
  }
}

