#### 3.5.1 用户态陷阱处理

```c
void usertrap(void) {
  // 检查是否来自用户态
  if((r_sstatus() & SSTATUS_SPP) != 0)
    panic("usertrap: not from user mode");

  // 设置内核陷阱向量
  w_stvec((uint64)kernelvec);

  struct proc *p = myproc();
  p->trapframe->epc = r_sepc();

  if(r_scause() == 8) {
    // 系统调用
    if(killed(p)) exit(-1);
    p->trapframe->epc += 4;  // 跳过 ecall 指令
    intr_on();
    syscall();
  } else if((which_dev = devintr()) != 0) {
    // 设备中断
  } else {
    // 未知异常
    printf("usertrap(): unexpected scause %p pid = %d\n", r_scause(), p->pid);
    setkilled(p);
  }

  if(killed(p)) exit(-1);

  // 时钟中断时让出 CPU
  if(which_dev == 2) yield();

  usertrapret();
}
```

#### 3.5.2 Trampoline 代码

```asm
uservec:    
    # 保存 a0 到 sscratch
    csrw sscratch, a0

    # 加载 TRAPFRAME 地址
    li a0, TRAPFRAME

    # 保存所有用户寄存器到 TRAPFRAME
    sd ra, 40(a0)
    sd sp, 48(a0)
    # ... 保存所有寄存器

    # 恢复 a0
    csrr t0, sscratch
    sd t0, 112(a0)

    # 设置内核栈指针
    ld sp, 8(a0)

    # 设置 hartid
    ld tp, 32(a0)

    # 加载 usertrap 地址
    ld t0, 16(a0)

    # 切换到内核页表
    ld t1, 0(a0)
    sfence.vma zero, zero
    csrw satp, t1
    sfence.vma zero, zero

    # 跳转到 usertrap
    jr t0
```

#### 3.5.3 内核态陷阱处理

```c
void kerneltrap() {
  uint64 sepc = r_sepc();
  uint64 sstatus = r_sstatus();
  uint64 scause = r_scause();

  if((sstatus & SSTATUS_SPP) == 0)
    panic("kerneltrap: not from supervisor mode");
  if(intr_get() != 0)
    panic("kerneltrap: interrupts enabled");

  if((which_dev = devintr()) == 0) {
    printf("scause %p\n", scause);
    panic("kerneltrap");
  }

  // 时钟中断时让出 CPU
  if(which_dev == 2 && myproc() != 0 && myproc()->state == RUNNING)
    yield();

  // 恢复寄存器
  w_sepc(sepc);
  w_sstatus(sstatus);
}
```

#### 3.5.4 设备中断处理

```c
int devintr() {
  uint64 scause = r_scause();

  if((scause & 0x8000000000000000L) && (scause & 0xff) == 9) {
    // 外部中断（PLIC）
    int irq = plic_claim();

    if(irq == UART0_IRQ) {
      uartintr();
    } else if(irq == VIRTIO0_IRQ) {
      virtio_disk_intr();
    }

    if(irq) plic_complete(irq);
    return 1;
  } else if(scause == 0x8000000000000005L) {
    // 时钟中断
    if(cpuid() == 0) clockintr();

    // 清除 STIP 位
    w_sip(r_sip() & ~(1<<5));
    set_next_trigger();
    return 2;
  }
  return 0;
}
```

